import { Effect, Schedule, Duration, Data } from "effect";

interface Email { readonly to: string; readonly subject: string; readonly body: string }

class TransientSmtpError extends Data.TaggedError("TransientSmtpError")<{ readonly message: string }> {}
class PermanentSmtpError extends Data.TaggedError("PermanentSmtpError")<{ readonly message: string }> {}

declare const rawSend: (e: Email) => Effect.Effect<void, TransientSmtpError | PermanentSmtpError>;

// Bounded schedule: exponential base, jittered, capped at 5 attempts.
const retryPolicy = Schedule.exponential(Duration.millis(200)).pipe(
  Schedule.jittered,
  Schedule.compose(Schedule.recurs(5)),
);

const sendOne = (e: Email): Effect.Effect<void, PermanentSmtpError> =>
  rawSend(e).pipe(
    Effect.retry({ schedule: retryPolicy, while: (err) => err._tag === "TransientSmtpError" }),
    Effect.catchTag("TransientSmtpError", (err) =>
      Effect.fail(new PermanentSmtpError({ message: `exhausted retries: ${err.message}` })),
    ),
  );

export const sendBatch = (emails: ReadonlyArray<Email>): Effect.Effect<ReadonlyArray<void>, PermanentSmtpError> =>
  Effect.gen(function* () {
    const sem = yield* Effect.makeSemaphore(4);
    return yield* Effect.all(
      emails.map((e) => sem.withPermits(1)(sendOne(e))),
      { concurrency: "unbounded" },
    );
  });
