import { Effect, Schedule, Duration, RateLimiter, Data } from "effect";

class SmtpTransient extends Data.TaggedError("SmtpTransient")<{ readonly code: number }> {}

interface Msg { readonly to: string; readonly body: string }

declare const rawSend: (m: Msg) => Effect.Effect<void, SmtpTransient>;

const retry = Schedule.exponential(Duration.millis(100)).pipe(
  Schedule.jittered,
  Schedule.compose(Schedule.recurs(4)),
);

export const makeSender = Effect.gen(function* () {
  // 10 permits / 1s window = 10 rps.
  const limiter = yield* RateLimiter.make({ limit: 10, interval: Duration.seconds(1) });
  const send = (m: Msg) =>
    limiter(rawSend(m)).pipe(Effect.retry(retry));
  return { send } as const;
});
