`Effect.catchTag` narrows the error union by its discriminant `_tag`. When an email send can fail with either a transient SMTP fault or a permanent rejection, we retry on the transient one and let `catchTag` replace exhausted transients with a permanent fault. The resulting effect still advertises `PermanentSmtpError` in its E channel so callers must handle it — you cannot accidentally swallow it.

```typescript
import { Effect, Schedule, Duration, Data } from "effect";

class Transient extends Data.TaggedError("Transient")<{ readonly reason: string }> {}
class Permanent extends Data.TaggedError("Permanent")<{ readonly reason: string }> {}

interface Email { readonly to: string; readonly body: string }

declare const rawSend: (e: Email) => Effect.Effect<void, Transient | Permanent>;

const policy = Schedule.exponential(Duration.millis(250)).pipe(
  Schedule.jittered,
  Schedule.compose(Schedule.recurs(3)),
);

export const send = (e: Email): Effect.Effect<void, Permanent> =>
  rawSend(e).pipe(
    Effect.retry({ schedule: policy, while: (err) => err._tag === "Transient" }),
    Effect.catchTag("Transient", (t) =>
      Effect.fail(new Permanent({ reason: `retry budget exhausted: ${t.reason}` })),
    ),
  );
```

