import { Effect, Schedule, Duration, Data } from "effect";

interface Msg { readonly id: string; readonly to: string; readonly html: string }

class RateLimited extends Data.TaggedError("RateLimited")<{ readonly retryAfterMs: number }> {}
class BadAddress extends Data.TaggedError("BadAddress")<{ readonly to: string }> {}

