const policy = Schedule.exponential(Duration.millis(200)).pipe(
  Schedule.jittered,
  Schedule.intersect(Schedule.recurs(6)),
);

const sendOne = (m: Msg): Effect.Effect<string, BadAddress> =>
  sendRaw(m).pipe(
    Effect.retry({ schedule: policy, while: (e) => e._tag === "RateLimited" }),
    Effect.catchTag("RateLimited", (e) =>
      Effect.fail(new BadAddress({ to: `dropped after ${e.retryAfterMs}ms budget` })),
    ),
  );

export const dispatch = (
  msgs: ReadonlyArray<Msg>,
): Effect.Effect<ReadonlyArray<string>, BadAddress> =>
  Effect.all(msgs.map(sendOne), { concurrency: 8 });
