`Effect.acquireRelease(acquire, release)` registers the release step on the current `Scope` the moment the resource is produced. Any failure or interruption after that point still runs the release — unlike a `try/finally`, you cannot forget it, and unlike manual `.catch()`, it runs on interrupts too. Wrapping the whole pipeline in `Effect.scoped` closes the scope at the end, releasing every handle deterministically.

```typescript
import { Effect, Data } from "effect";

interface Handle { readonly path: string; readonly close: () => Promise<void> }

class OpenError extends Data.TaggedError("OpenError")<{ readonly path: string }> {}
class IoError extends Data.TaggedError("IoError")<{ readonly reason: string }> {}

declare const openHandle: (p: string) => Effect.Effect<Handle, OpenError>;
declare const readAll: (h: Handle) => Effect.Effect<ReadonlyArray<string>, IoError>;
declare const writeAll: (h: Handle, lines: ReadonlyArray<string>) => Effect.Effect<void, IoError>;

const withHandle = (path: string) =>
  Effect.acquireRelease(
    openHandle(path),
    (h) => Effect.promise(() => h.close()),
  );

export const upperCaseFile = (inPath: string, outPath: string) =>
  Effect.scoped(
    Effect.gen(function* () {
      const inH = yield* withHandle(inPath);
      const outH = yield* withHandle(outPath);
      const lines = yield* readAll(inH);
      yield* writeAll(outH, lines.map((l) => l.toUpperCase()));
    }),
  );
```

