import { Effect, Data } from "effect";

interface Row { readonly a: string; readonly b: string }

class ReadFail extends Data.TaggedError("ReadFail")<{ readonly path: string }> {}
class WriteFail extends Data.TaggedError("WriteFail")<{ readonly path: string }> {}
class ParseFail extends Data.TaggedError("ParseFail")<{ readonly line: number }> {}

declare const readText: (p: string) => Effect.Effect<string, ReadFail>;
declare const writeText: (p: string, s: string) => Effect.Effect<void, WriteFail>;

const parseRow = (line: string, idx: number): Effect.Effect<Row, ParseFail> => {
  const parts = line.split(",");
  if (parts.length !== 2) return Effect.fail(new ParseFail({ line: idx }));
  return Effect.succeed({ a: parts[0]!, b: parts[1]! });
};

export const csvToJson = (
  src: string,
  dst: string,
): Effect.Effect<number, ReadFail | WriteFail | ParseFail> =>
  Effect.gen(function* () {
    const raw = yield* readText(src);
    const lines = raw.split(/\r?\n/).filter((l) => l.trim().length > 0);
    const rows = yield* Effect.all(lines.map(parseRow));
    yield* writeText(dst, JSON.stringify(rows));
    return rows.length;
  });
