import * as E from "fp-ts/Either";
import { pipe } from "fp-ts/function";

interface Claims { readonly sub: string; readonly exp: number }

type JwtError =
  | { readonly _tag: "Malformed" }
  | { readonly _tag: "BadSignature" }
  | { readonly _tag: "BadPayload"; readonly reason: string };

const splitToken = (token: string): E.Either<JwtError, [string, string, string]> => {
  const parts = token.split(".");
  return parts.length === 3
    ? E.right([parts[0]!, parts[1]!, parts[2]!])
    : E.left({ _tag: "Malformed" });
};

const decodePayload = (b64: string): E.Either<JwtError, Claims> =>
  E.tryCatch<JwtError, Claims>(
    () => {
      const raw = Buffer.from(b64, "base64url").toString("utf8");
      const parsed = JSON.parse(raw) as Partial<Claims>;
      if (typeof parsed.sub !== "string" || typeof parsed.exp !== "number") {
        throw new Error("missing sub/exp");
      }
      return { sub: parsed.sub, exp: parsed.exp };
    },
    (u) => ({ _tag: "BadPayload", reason: u instanceof Error ? u.message : String(u) }),
  );

declare const hmacMatches: (header: string, payload: string, sig: string, secret: string) => boolean;

const checkSig = (secret: string) => ([h, p, s]: [string, string, string]): E.Either<JwtError, string> =>
  hmacMatches(h, p, s, secret) ? E.right(p) : E.left({ _tag: "BadSignature" });

export const verify = (secret: string) => (token: string): E.Either<JwtError, Claims> =>
  pipe(
    splitToken(token),
    E.chainW(checkSig(secret)),
    E.chainW(decodePayload),
  );
```

