import * as E from "fp-ts/Either";
import * as RNEA from "fp-ts/ReadonlyNonEmptyArray";
import { getSemigroup } from "fp-ts/NonEmptyArray";
import { sequenceT } from "fp-ts/Apply";
import { pipe } from "fp-ts/function";

interface Claims { readonly sub: string; readonly exp: number; readonly iss: string }

type ClaimError = string;

const V = E.getApplicativeValidation(getSemigroup<ClaimError>());

const nonEmpty = (s: string): E.Either<RNEA.ReadonlyNonEmptyArray<ClaimError>, string> =>
  s.length > 0 ? E.right(s) : E.left(["sub is empty"]);

const future = (e: number): E.Either<RNEA.ReadonlyNonEmptyArray<ClaimError>, number> =>
  e > Date.now() / 1000 ? E.right(e) : E.left(["exp in the past"]);

const issuer = (i: string): E.Either<RNEA.ReadonlyNonEmptyArray<ClaimError>, string> =>
  i === "auth.example" ? E.right(i) : E.left(["bad issuer"]);

export const validate = (c: Claims) =>
  pipe(
    sequenceT(V)(nonEmpty(c.sub), future(c.exp), issuer(c.iss)),
    E.map(([sub, exp, iss]) => ({ sub, exp, iss })),
  );
