A JWT verifier has three distinct failure modes that a caller wants to react to differently: malformed token, bad signature, expired claim. Throwing collapses all three into `unknown`; fp-ts `Either<JwtError, Claims>` keeps the union in the type and forces exhaustive handling at the call site via `E.match`. The flow is also pure — no I/O, no promises — so it composes inside larger `TaskEither` pipelines without adding effect overhead.

```typescript
import * as E from "fp-ts/Either";
import { pipe } from "fp-ts/function";

interface Claims { readonly sub: string; readonly exp: number }

type JwtError =
  | { readonly _tag: "Malformed" }
  | { readonly _tag: "BadSignature" }
  | { readonly _tag: "Expired"; readonly at: number };

const parse = (raw: string): E.Either<JwtError, Claims> => {
  const [, body] = raw.split(".");
  if (!body) return E.left({ _tag: "Malformed" });
  try {
    const parsed = JSON.parse(Buffer.from(body, "base64url").toString()) as Partial<Claims>;
    if (typeof parsed.sub !== "string" || typeof parsed.exp !== "number") {
      return E.left({ _tag: "Malformed" });
    }
    return E.right({ sub: parsed.sub, exp: parsed.exp });
  } catch { return E.left({ _tag: "Malformed" }); }
};

declare const verifySig: (raw: string) => E.Either<JwtError, string>;

const checkExp = (c: Claims): E.Either<JwtError, Claims> =>
  c.exp * 1000 > Date.now() ? E.right(c) : E.left({ _tag: "Expired", at: c.exp });

export const verify = (raw: string): E.Either<JwtError, Claims> =>
  pipe(verifySig(raw), E.chainW(parse), E.chainW(checkExp));
```

