`Effect.catchTag(tag, handler)` narrows the error union on its `_tag` discriminant. Chaining three `catchTag` calls at the resolver boundary is how you translate domain errors (`NotFound`, `Forbidden`, `ValidationError`) into transport-layer responses (404, 403, 400) without losing exhaustiveness: if you forget a tag, the E channel of the final effect still carries the unmapped one and the compiler complains.

```typescript
import { Effect, Data } from "effect";

class NotFound extends Data.TaggedError("NotFound")<{ readonly id: string }> {}
class Forbidden extends Data.TaggedError("Forbidden")<{}> {}
class ValidationError extends Data.TaggedError("ValidationError")<{ readonly field: string }> {}

interface Resp { readonly status: number; readonly body: string }

export const toHttp = <A>(
  eff: Effect.Effect<A, NotFound | Forbidden | ValidationError>,
): Effect.Effect<Resp> =>
  eff.pipe(
    Effect.map((a): Resp => ({ status: 200, body: JSON.stringify(a) })),
    Effect.catchTag("NotFound", (e) => Effect.succeed({ status: 404, body: `missing ${e.id}` })),
    Effect.catchTag("Forbidden", () => Effect.succeed({ status: 403, body: "forbidden" })),
    Effect.catchTag("ValidationError", (e) =>
      Effect.succeed({ status: 400, body: `bad ${e.field}` }),
    ),
  );
```

