import { Effect, Match, Data } from "effect";

type InMsg =
  | { readonly type: "ping" }
  | { readonly type: "chat"; readonly body: string }
  | { readonly type: "close"; readonly code: number };

class DecodeErr extends Data.TaggedError("DecodeErr")<{ readonly raw: string }> {}
class UnknownType extends Data.TaggedError("UnknownType")<{ readonly type: string }> {}

const decode = (raw: string): Effect.Effect<InMsg, DecodeErr> =>
  Effect.try({
    try: () => {
      const parsed = JSON.parse(raw) as InMsg;
      if (parsed.type !== "ping" && parsed.type !== "chat" && parsed.type !== "close") {
        throw new Error(`unknown type ${String((parsed as { type: string }).type)}`);
      }
      return parsed;
    },
    catch: () => new DecodeErr({ raw }),
  });

declare const onPing: () => Effect.Effect<void>;
declare const onChat: (body: string) => Effect.Effect<void>;
declare const onClose: (code: number) => Effect.Effect<void>;

export const handle = (raw: string): Effect.Effect<void, DecodeErr | UnknownType> =>
  Effect.gen(function* () {
    const msg = yield* decode(raw);
    yield* Match.value(msg).pipe(
      Match.tag("ping", () => onPing()),
      Match.tag("chat", (m) => onChat(m.body)),
      Match.tag("close", (m) => onClose(m.code)),
      Match.exhaustive,
    );
  });
```

