import { Effect, Match } from "effect";

type Frame =
  | { readonly _tag: "text"; readonly body: string }
  | { readonly _tag: "binary"; readonly bytes: Uint8Array }
  | { readonly _tag: "close" };

const handleText = (s: string): Effect.Effect<number> => Effect.succeed(s.length);
const handleBinary = (b: Uint8Array): Effect.Effect<number> => Effect.succeed(b.byteLength);
const handleClose = (): Effect.Effect<number> => Effect.succeed(-1);

export const route = (f: Frame): Effect.Effect<number> =>
  Match.value(f).pipe(
    Match.tag("text", (t) => handleText(t.body)),
    Match.tag("binary", (b) => handleBinary(b.bytes)),
    Match.tag("close", () => handleClose()),
    Match.exhaustive,
  );
```

`Match.exhaustive` is the final step of a `Match.value(...).pipe(...)` pipeline. It compiles only when the union of remaining unmatched variants is `never` — in practice, after you've provided a `Match.tag` branch for every discriminator value. Add a new variant to the input union and the exhaustive check becomes the one place the compiler tells you a branch is missing; skip it and a typo-ed tag silently falls through.

```typescript
import { Effect, Match } from "effect";

type Ev =
  | { readonly _tag: "join"; readonly room: string }
  | { readonly _tag: "leave"; readonly room: string }
  | { readonly _tag: "msg"; readonly room: string; readonly body: string };

declare const publish: (room: string, body: string) => Effect.Effect<void>;
declare const addMember: (room: string) => Effect.Effect<void>;
declare const removeMember: (room: string) => Effect.Effect<void>;

export const route = (e: Ev): Effect.Effect<void> =>
  Match.value(e).pipe(
    Match.tag("join", (x) => addMember(x.room)),
    Match.tag("leave", (x) => removeMember(x.room)),
    Match.tag("msg", (x) => publish(x.room, x.body)),
    Match.exhaustive,
