import { Effect, Queue, Data } from "effect";

interface Frame { readonly id: string; readonly body: string }

class HandlerError extends Data.TaggedError("HandlerError")<{ readonly id: string }> {}

declare const handleFrame: (f: Frame) => Effect.Effect<void, HandlerError>;

export const runDispatcher = (
  q: Queue.Queue<Frame>,
): Effect.Effect<void, HandlerError> =>
  Effect.gen(function* () {
    // Drain forever; forEach with concurrency gives us the worker pool.
    yield* Effect.forever(
      Effect.gen(function* () {
        const batch = yield* Queue.takeAll(q);
        if (batch.length === 0) {
          yield* Queue.take(q).pipe(Effect.map((f) => [f] as const));
        }
        yield* Effect.forEach(batch, handleFrame, { concurrency: 16, discard: true });
      }),
    );
  });
