import { Effect, Queue, Fiber, Data } from "effect";

interface Job { readonly id: string; readonly run: () => Effect.Effect<void, JobError> }

class JobError extends Data.TaggedError("JobError")<{ readonly id: string }> {}

const worker = (q: Queue.Queue<Job>): Effect.Effect<void> =>
  Effect.forever(
    Effect.gen(function* () {
      const job = yield* Queue.take(q);
      yield* job.run().pipe(Effect.catchTag("JobError", () => Effect.void));
    }),
  );

export const makeRunner = (workers: number) =>
  Effect.gen(function* () {
    const q = yield* Queue.bounded<Job>(1024);
    const fibers: Fiber.RuntimeFiber<void>[] = [];
    for (let i = 0; i < workers; i++) {
      const f = yield* Effect.fork(worker(q));
      fibers.push(f);
    }
    const submit = (j: Job) => Queue.offer(q, j);
    const shutdown = Effect.gen(function* () {
      yield* Queue.shutdown(q);
      yield* Fiber.interruptAll(fibers);
    });
    return { submit, shutdown } as const;
  });
