```typescript
import { Effect, Queue } from "effect";

interface Job { readonly id: string }

export const makeProducer = Effect.gen(function* () {
  // bounded: `offer` suspends the caller when the queue is full,
  // yielding natural back-pressure without dropping work.
  const q = yield* Queue.bounded<Job>(64);
  const produce = (j: Job) => Queue.offer(q, j);
  const take = Queue.take(q);
  return { produce, take, q } as const;
});
```

`Effect.fork` starts each worker as a fiber and returns a handle without blocking the supervisor. When shutdown time comes the supervisor calls `Fiber.interruptAll`, which sends an interrupt signal to every fiber in flight. Because Effect propagates interrupts through `Effect.gen` and `pipe`, any resource acquired via `acquireRelease` inside a worker still releases cleanly — you get cooperative cancellation without ad-hoc flags.

```typescript
import { Effect, Queue, Fiber, Data } from "effect";

class JobFailed extends Data.TaggedError("JobFailed")<{ readonly id: string }> {}

interface Job { readonly id: string; readonly work: Effect.Effect<void, JobFailed> }

const workerLoop = (q: Queue.Queue<Job>) =>
  Effect.forever(
    Effect.gen(function* () {
      const j = yield* Queue.take(q);
      yield* j.work.pipe(Effect.catchTag("JobFailed", () => Effect.void));
    }),
  );

export const runPool = Effect.gen(function* () {
  const q = yield* Queue.bounded<Job>(256);
  const f1 = yield* Effect.fork(workerLoop(q));
  const f2 = yield* Effect.fork(workerLoop(q));
  const f3 = yield* Effect.fork(workerLoop(q));
  const shutdown = Fiber.interruptAll([f1, f2, f3]);
  return { submit: (j: Job) => Queue.offer(q, j), shutdown } as const;
});
```

