import { Effect, Schedule, Duration, Queue, Data } from "effect";

interface Job { readonly id: string; readonly work: Effect.Effect<void, JobFailed> }

class JobFailed extends Data.TaggedError("JobFailed")<{ readonly id: string }> {}
class DeadLetter extends Data.TaggedError("DeadLetter")<{ readonly id: string }> {}

const policy = Schedule.exponential(Duration.millis(100)).pipe(
  Schedule.jittered,
  Schedule.compose(Schedule.recurs(3)),
);

const runOne = (j: Job): Effect.Effect<void, DeadLetter> =>
  j.work.pipe(
    Effect.retry(policy),
    Effect.catchTag("JobFailed", () => Effect.fail(new DeadLetter({ id: j.id }))),
  );

export const makeRunner = (q: Queue.Queue<Job>, dlq: Queue.Queue<string>) =>
  Effect.forever(
    Effect.gen(function* () {
      const j = yield* Queue.take(q);
      yield* runOne(j).pipe(
        Effect.catchTag("DeadLetter", (e) => Queue.offer(dlq, e.id)),
      );
    }),
  );
