import { Effect, Queue } from "effect";

interface Job { readonly id: string }

export const makePriority = Effect.gen(function* () {
  const hi = yield* Queue.unbounded<Job>();
  const lo = yield* Queue.unbounded<Job>();
  // take favours hi — checks it first, only polls lo if hi is empty.
  const take: Effect.Effect<Job> = Effect.gen(function* () {
    const peek = yield* Queue.poll(hi);
    if (peek._tag === "Some") return peek.value;
    return yield* Queue.take(lo);
  });
  return {
    offerHi: (j: Job) => Queue.offer(hi, j),
    offerLo: (j: Job) => Queue.offer(lo, j),
    take,
  } as const;
});
