import { Effect, Data } from "effect";

interface Charge { readonly amount: number; readonly cardToken: string }
interface Receipt { readonly id: string; readonly amount: number }

class Decline extends Data.TaggedError("Decline")<{ readonly reason: string }> {}
class NetworkErr extends Data.TaggedError("NetworkErr")<{ readonly cause: string }> {}
class InvalidCard extends Data.TaggedError("InvalidCard")<{ readonly field: string }> {}

declare const rawCharge: (body: string) => Promise<{ id: string }>;

const validate = (c: Charge): Effect.Effect<Charge, InvalidCard> => {
  if (!c.cardToken.startsWith("tok_")) {
    return Effect.fail(new InvalidCard({ field: "cardToken" }));
  }
  if (c.amount <= 0) return Effect.fail(new InvalidCard({ field: "amount" }));
  return Effect.succeed(c);
};

export const charge = (c: Charge): Effect.Effect<Receipt, Decline | NetworkErr | InvalidCard> =>
  Effect.gen(function* () {
    const valid = yield* validate(c);
    const resp = yield* Effect.tryPromise({
      try: () => rawCharge(JSON.stringify(valid)),
      catch: (u) =>
        u instanceof Error && u.message.startsWith("decline:")
          ? new Decline({ reason: u.message.slice("decline:".length) })
          : new NetworkErr({ cause: u instanceof Error ? u.message : String(u) }),
    });
    return { id: resp.id, amount: valid.amount };
  });
