import { Effect, Schedule, Duration, Data } from "effect";

class Decline extends Data.TaggedError("Decline")<{ readonly reason: string }> {}
class NetworkErr extends Data.TaggedError("NetworkErr")<{ readonly status: number }> {}
class InvalidCard extends Data.TaggedError("InvalidCard")<{ readonly field: string }> {}

interface Charge { readonly amount: number; readonly cardToken: string }
interface Receipt { readonly id: string }

interface GwResp { readonly ok: boolean; readonly status: number; readonly body: { readonly id?: string; readonly code?: string } }

declare const call: (body: Charge) => Promise<GwResp>;

const classify = (r: GwResp): Effect.Effect<Receipt, Decline | NetworkErr> => {
  if (r.ok && r.body.id !== undefined) return Effect.succeed({ id: r.body.id });
  if (r.status >= 500) return Effect.fail(new NetworkErr({ status: r.status }));
  return Effect.fail(new Decline({ reason: r.body.code ?? "unknown" }));
};

const policy = Schedule.recurs(2); // 1 attempt + 2 retries = 3 total.

export const charge = (c: Charge): Effect.Effect<Receipt, Decline | NetworkErr | InvalidCard> =>
  Effect.gen(function* () {
    if (!c.cardToken) return yield* Effect.fail(new InvalidCard({ field: "cardToken" }));
    const resp = yield* Effect.tryPromise({
      try: () => call(c),
      catch: () => new NetworkErr({ status: 0 }),
    });
    return yield* classify(resp);
  }).pipe(
    Effect.retry({ schedule: policy, while: (e) => e._tag === "NetworkErr" }),
  );
```

